// Nó 9 — Parse Resposta IA
const iaResponse = $('Message a model').item.json;
const dadosOriginais = $('Code Node - Montar Prompt').item.json;

let responseText = '';
if (iaResponse.message) {
  responseText = iaResponse.message;
} else if (iaResponse.content && Array.isArray(iaResponse.content)) {
  responseText = iaResponse.content[0].text;
} else if (iaResponse.text) {
  responseText = iaResponse.text;
} else {
  responseText = JSON.stringify(iaResponse);
}

let analise;
try {
  const clean = responseText.replace(/```json|```/g, '').trim();
  analise = JSON.parse(clean);
} catch (e) {
  return [{
    json: {
      ...dadosOriginais,
      deve_notificar: false,
      erro_parse: true,
      resposta_raw: responseText
    }
  }];
}

const userMap = dadosOriginais.userMap || {};

const gerarMencaoHTML = (userId) => {
  let nome = null;
  for (const [key, val] of Object.entries(userMap)) {
    if (Number(val) === Number(userId)) {
      nome = key;
      break;
    }
  }
  if (!nome) return '';
  const nomeFormatado = nome.toLowerCase().replace(/\s+/g, '-');
  return `<a class="user_mention_editor router" href="https://contato-serv.monday.com/users/${userId}-${nomeFormatado}" data-mention-type="User" data-mention-id="${userId}" target="_blank" rel="noopener noreferrer">@${nome}</a>`;
};

// IDs de quem DEVE (cobrados)
const todosIdsDevedores = [];
if (analise.user_id_quem_deve) {
  todosIdsDevedores.push(Number(analise.user_id_quem_deve));
}
if (analise.user_ids_adicionais && Array.isArray(analise.user_ids_adicionais)) {
  analise.user_ids_adicionais.forEach(id => {
    if (id && !todosIdsDevedores.includes(Number(id))) {
      todosIdsDevedores.push(Number(id));
    }
  });
}

// IDs do PSC (ciência) — garante que não repete devedores
const todosIdsPSC = [];
if (analise.user_ids_psc && Array.isArray(analise.user_ids_psc)) {
  analise.user_ids_psc.forEach(id => {
    const numId = Number(id);
    if (numId && !todosIdsDevedores.includes(numId) && !todosIdsPSC.includes(numId)) {
      todosIdsPSC.push(numId);
    }
  });
}

// Menções HTML dos devedores
const mencoesDevedoresHTML = todosIdsDevedores
  .map(id => gerarMencaoHTML(id))
  .filter(m => m !== '')
  .join(' ');

// Menções HTML do PSC
const mencoesPSCHTML = todosIdsPSC
  .map(id => gerarMencaoHTML(id))
  .filter(m => m !== '')
  .join(' ');

// Converter markdown residual para HTML
const converterMarkdown = (texto) => {
  return String(texto || '')
    .replace(/\*\*(.+?)\*\*/g, '<b>$1</b>')
    .replace(/\*(.+?)\*/g, '<i>$1</i>');
};

// Limpar corpo de texto:
// 1. Remove @mentions falsas (a IA escreve @Nome mas isso não marca ninguém no Monday)
// 2. Remove qualquer linha "PSC:" que a IA tenha colocado no corpo
//    (o PSC real é montado abaixo com HTML de menção funcional)
const limparCorpo = (texto) => {
  let limpo = String(texto || '');
  // Remove @mentions (mantém só o nome sem @)
  limpo = limpo.replace(/@([A-ZÀ-Ü][a-zà-ü]+(?:\s+[A-ZÀ-Ü][a-zà-ü]+)*)/g, '$1');
  // Remove linhas que começam com "PSC:" ou "PSC :" (a IA às vezes duplica)
  limpo = limpo.replace(/\n?\s*PSC\s*:.*$/gim, '');
  return limpo.trim();
};

// Montar mensagem completa: menções HTML + corpo limpo + seção PSC (se houver)
let mensagemMonday = '';
if (analise.deve_notificar) {
  const cabecalho = `<p>${mencoesDevedoresHTML}</p>`;
  const corpoLimpo = limparCorpo(analise.mensagem_monday);
  const corpo = `<p>${converterMarkdown(corpoLimpo)}</p>`;
  const psc = mencoesPSCHTML
    ? `<p>PSC: ${mencoesPSCHTML}</p>`
    : '';
  mensagemMonday = cabecalho + corpo + psc;
}

const linkDemanda = `https://contato-serv.monday.com/boards/${dadosOriginais.boardID}/pulses/${dadosOriginais.pulseID}`;

return [{
  json: {
    deve_notificar: analise.deve_notificar,
    motivo: analise.motivo,
    quem_deve: analise.quem_deve,
    nome_quem_deve: analise.nome_quem_deve,
    user_id_quem_deve: analise.user_id_quem_deve,
    user_ids_adicionais: analise.user_ids_adicionais || [],
    user_ids_psc: todosIdsPSC,
    urgencia: analise.urgencia,
    prazo_detectado: analise.prazo_detectado,
    prazo_vencido: analise.prazo_vencido,
    mensagem_monday_html: mensagemMonday,
    mensagem_monday: analise.mensagem_monday,
    mensagem_whatsapp: analise.mensagem_whatsapp,
    resumo_demanda: analise.resumo_demanda || '',
    setores_envolvidos: analise.setores_envolvidos,
    pulseID: dadosOriginais.pulseID,
    boardID: dadosOriginais.boardID,
    itemName: dadosOriginais.itemName,
    itemId: dadosOriginais.itemId,
    setorDemandante: dadosOriginais.setorDemandante,
    setorDemandado: dadosOriginais.setorDemandado,
    horas_inativo: dadosOriginais.horas_inativo,
